const businesses = $input.all().map(i => i.json);
const flat = Array.isArray(businesses[0]) ? businesses[0] : businesses;

// Output each business that has its own Supabase instance for customer data
return flat.filter(b => b.supabase_url).map(b => ({
  json: {
    businessId: b.business_id,
    businessName: b.name,
    siteUrl: b.site_url || '',
    supabaseUrl: b.supabase_url,
    supabaseAnonKey: b.supabase_anon_key || '{{ $env.SUPABASE_ANON_KEY }}'
  }
}));

const customers = $input.all().map(i => i.json);
const allCustomers = Array.isArray(customers[0]) ? customers[0] : customers;
const bizData = $('Split Per Business').item.json;

const now = new Date();
const thirtyDaysAgo = new Date(now - 30 * 24 * 60 * 60 * 1000);
const ninetyDaysAgo = new Date(now - 90 * 24 * 60 * 60 * 1000);
const fourteenDaysAgo = new Date(now - 14 * 24 * 60 * 60 * 1000);

const eligible = [];

for (const c of allCustomers) {
  if (!c.email || !c.name) continue;
  const createdAt = new Date(c.created_at);
  if (createdAt > thirtyDaysAgo) continue;
  if (c.churn_risk_status === 'high' || c.churn_risk_status === 'churned') continue;
  if (c.review_requested_at) {
    const lastAsked = new Date(c.review_requested_at);
    if (lastAsked > ninetyDaysAgo) continue;
  }
  if (c.last_login_at) {
    const lastLogin = new Date(c.last_login_at);
    if (lastLogin < fourteenDaysAgo) continue;
  }

  const daysSinceSignup = Math.floor((now - createdAt) / (1000 * 60 * 60 * 24));
  eligible.push({
    json: {
      id: c.id,
      email: c.email,
      name: c.name,
      daysSinceSignup,
      businessId: bizData.businessId,
      businessName: bizData.businessName,
      siteUrl: bizData.siteUrl,
      supabaseUrl: bizData.supabaseUrl
    }
  });
  if (eligible.length >= 10) break;
}

if (eligible.length === 0) {
  return [{ json: { _noEligible: true, count: 0, businessId: bizData.businessId, businessName: bizData.businessName } }];
}

return eligible;

const { name, email, daysSinceSignup, businessName, siteUrl } = $input.first().json;
const domain = (siteUrl || '').replace(/^https?:\/\//, '').replace(/\/.*$/, '');

const timePhrase = daysSinceSignup > 60 ? 'a couple months' : 'about a month';

const html = `
<!DOCTYPE html>
<html>
<head>
  <meta charset="utf-8">
  <meta name="viewport" content="width=device-width, initial-scale=1.0">
  <style>
    body { margin: 0; padding: 0; background-color: #f4f4f5; font-family: 'Segoe UI', Arial, sans-serif; }
    .container { max-width: 600px; margin: 0 auto; background: #ffffff; border-radius: 12px; overflow: hidden; }
    .header { background: linear-gradient(135deg, #dc2626, #991b1b); padding: 32px; text-align: center; }
    .header h1 { color: #ffffff; margin: 0; font-size: 22px; font-weight: 700; }
    .body { padding: 32px; }
    .body p { color: #3f3f46; font-size: 15px; line-height: 1.7; margin: 0 0 16px; }
    .review-links { margin: 24px 0; }
    .review-btn { display: inline-block; background: #dc2626; color: #ffffff; text-decoration: none; padding: 12px 24px; border-radius: 8px; font-weight: 600; font-size: 14px; margin: 6px 8px 6px 0; }
    .review-btn.secondary { background: #18181b; }
    .footer { padding: 20px 32px; background: #fafafa; text-align: center; }
    .footer p { color: #a1a1aa; font-size: 12px; margin: 0; }
    .footer a { color: #dc2626; text-decoration: none; }
  </style>
</head>
<body>
  <div style="padding: 24px;">
    <div class="container">
      <div class="header">
        <h1>${businessName}</h1>
      </div>
      <div class="body">
        <p>Hey ${name},</p>
        <p>You've been on ${businessName} for ${timePhrase} now. If it's been useful, would you mind leaving a quick review? Takes about 60 seconds and it really helps other people find us.</p>
        <div class="review-links">
          <a href="https://www.g2.com/products/${domain}/reviews" class="review-btn">Leave a review on G2</a>
          <a href="https://www.capterra.com/p/${domain}/reviews/new" class="review-btn secondary">Leave a review on Capterra</a>
        </div>
        <p><strong>But if something's not working right, just reply to this email instead.</strong> I'd way rather fix it than have you leave a bad review.</p>
        <p>Thanks,<br>Shalin</p>
      </div>
      <div class="footer">
        <p>${businessName}</p>
        <p><a href="${siteUrl || '#'}">${domain}</a></p>
      </div>
    </div>
  </div>
</body>
</html>
`.trim();

return [{
  json: {
    ...$input.first().json,
    emailSubject: 'Quick favor, ' + name + '?',
    emailHtml: html
  }
}];

const customer = $('Build Review Request Email').first().json;
const resendResponse = $input.first().json;
const sent = !!(resendResponse.id);
return [{ json: { customerId: customer.id, email: customer.email, name: customer.name, sent, resendId: resendResponse.id || null, error: resendResponse.error || null, businessId: customer.businessId, businessName: customer.businessName, supabaseUrl: customer.supabaseUrl } }];

const items = $input.all();
let sentCount = 0, failedCount = 0;
const names = [];
const businessesSeen = new Set();

for (const item of items) {
  const data = item.json;
  if (data.sent || data.resendId) {
    sentCount++;
    if (data.name) names.push(data.name);
    if (data.businessName) businessesSeen.add(data.businessName);
  } else if (data.error) {
    failedCount++;
  }
}

const message = '*Review Collector Weekly Summary*\n\n' +
  'Review requests sent: *' + sentCount + '*\n' +
  (failedCount > 0 ? 'Failed to send: *' + failedCount + '*\n' : '') +
  (names.length > 0 ? 'Customers contacted: ' + names.join(', ') + '\n' : '') +
  'Businesses: ' + Array.from(businessesSeen).join(', ') + '\n' +
  '\nWeek of ' + new Date().toISOString().split('T')[0];

return [{ json: { text: message, sentCount, failedCount } }];

return [{ json: { sent: false, sentCount: 0, text: '*Review Collector Weekly Summary*

No eligible customers to request reviews from this week.

Week of ' + new Date().toISOString().split('T')[0] } }];

const payload = $input.first().json.body || $input.first().json;
const customerId = payload.customerId || payload.customer_id || '';
const email = payload.email || '';
const name = payload.name || 'there';
const platform = payload.platform || 'unknown';
const rating = payload.rating || 0;
const reviewText = payload.review_text || '';
const businessId = payload.business_id || 'unknown';

if (!email && !customerId) throw new Error('Missing required field: email or customerId');

return [{ json: { customerId, email, name, platform, rating, reviewText, isPositive: rating >= 4, businessId } }];

const { name, email, platform, rating, businessId } = $input.first().json;

const html = `
<!DOCTYPE html>
<html><head><meta charset="utf-8"><style>
  body { margin: 0; padding: 0; background-color: #f4f4f5; font-family: 'Segoe UI', Arial, sans-serif; }
  .container { max-width: 600px; margin: 0 auto; background: #ffffff; border-radius: 12px; overflow: hidden; }
  .header { background: linear-gradient(135deg, #dc2626, #991b1b); padding: 32px; text-align: center; }
  .header h1 { color: #ffffff; margin: 0; font-size: 22px; }
  .body { padding: 32px; }
  .body p { color: #3f3f46; font-size: 15px; line-height: 1.7; margin: 0 0 16px; }
</style></head>
<body><div style="padding: 24px;"><div class="container">
  <div class="header"><h1>Thank You!</h1></div>
  <div class="body">
    <p>Hey ${name},</p>
    <p>Just saw your ${rating}-star review on ${platform}. Seriously, thank you.</p>
    <p>Would you be open to a short testimonial? Just a sentence or two about your experience.</p>
    <p>Thanks,<br>Shalin</p>
  </div>
</div></div></body></html>`.trim();

return [{ json: { ...$input.first().json, thankYouSubject: 'Thanks for the review, ' + name + '!', thankYouHtml: html } }];
